import{_ as p,o as r,c as t,b as a,w as i,d as s,e as c,a as o,r as n}from"./app.dec15874.js";const g=JSON.parse('{"title":"运行多个 npm script 的各种姿势","description":"","frontmatter":{"createTime":"2022/11/02","tag":"工程化,npm"},"headers":[{"level":2,"title":"让多个 npm script 串行？&&","slug":"让多个-npm-script-串行","link":"#让多个-npm-script-串行","children":[]},{"level":2,"title":"让多个 npm script 并行？ &","slug":"让多个-npm-script-并行","link":"#让多个-npm-script-并行","children":[]},{"level":2,"title":"wait","slug":"wait","link":"#wait","children":[]},{"level":2,"title":"有没有更好的管理方式？  npm-run-all","slug":"有没有更好的管理方式-npm-run-all","link":"#有没有更好的管理方式-npm-run-all","children":[{"level":3,"title":"下载依赖","slug":"下载依赖","link":"#下载依赖","children":[]},{"level":3,"title":"使用","slug":"使用","link":"#使用","children":[]},{"level":3,"title":"如何让多个 npm script 并行执行？","slug":"如何让多个-npm-script-并行执行","link":"#如何让多个-npm-script-并行执行","children":[]}]}],"relativePath":"engineering/npm/more-script/index.md","lastUpdated":1667401036000}'),d={name:"engineering/npm/more-script/index.md"},m=s("h1",{id:"运行多个-npm-script-的各种姿势",tabindex:"-1"},[c("运行多个 npm script 的各种姿势 "),s("a",{class:"header-anchor",href:"#运行多个-npm-script-的各种姿势","aria-hidden":"true"},"#")],-1),h=o(`<h2 id="让多个-npm-script-串行" tabindex="-1">让多个 npm script 串行？&amp;&amp; <a class="header-anchor" href="#让多个-npm-script-串行" aria-hidden="true">#</a></h2><p>在我们运行测试之前确保我们的代码都通过代码检查会是比较不错的实践，这也是让多个 npm script 串行的典型用例，实现方式也比较简单，只需要用 &amp;&amp; 符号把多条 npm script 按先后顺序串起来即可</p><h2 id="让多个-npm-script-并行" tabindex="-1">让多个 npm script 并行？ &amp; <a class="header-anchor" href="#让多个-npm-script-并行" aria-hidden="true">#</a></h2><p>在严格串行的情况下，我们必须要确保代码中没有编码规范问题才能运行测试，在某些时候可能并不是我们想要的，因为我们真正需要的是，代码变更时同时给出测试结果和测试运行结果。这就需要把子命令的运行从串行改成并行，实现方式更简单，把连接多条命令的 &amp;&amp; 符号替换成 &amp; 即可。</p><h2 id="wait" tabindex="-1">wait <a class="header-anchor" href="#wait" aria-hidden="true">#</a></h2><p>npm 内置支持的多条命令并行跟 js 里面同时发起多个异步请求非常类似，它只负责触发多条命令，而不管结果的收集</p><p>加上 wait 的额外好处是，如果我们在任何子命令中启动了长时间运行的进程，比如启用了 mocha 的 --watch 配置，可以使用 ctrl + c 来结束进程，如果没加的话，你就没办法直接结束启动到后台的进程。</p><h2 id="有没有更好的管理方式-npm-run-all" tabindex="-1">有没有更好的管理方式？ npm-run-all <a class="header-anchor" href="#有没有更好的管理方式-npm-run-all" aria-hidden="true">#</a></h2><p>用如下命令将 npm-run-all 添加到项目依赖中：</p><h3 id="下载依赖" tabindex="-1">下载依赖 <a class="header-anchor" href="#下载依赖" aria-hidden="true">#</a></h3><div class="language-js line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">npm i npm</span><span style="color:#89DDFF;">-</span><span style="color:#A6ACCD;">run</span><span style="color:#89DDFF;">-</span><span style="color:#A6ACCD;">all </span><span style="color:#89DDFF;">-</span><span style="color:#A6ACCD;">D</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="使用" tabindex="-1">使用 <a class="header-anchor" href="#使用" aria-hidden="true">#</a></h3><div class="language-js line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">npm</span><span style="color:#89DDFF;">-</span><span style="color:#A6ACCD;">run</span><span style="color:#89DDFF;">-</span><span style="color:#A6ACCD;">all xxx1 xxx2 xxx3</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>npm-run-all 还支持通配符匹配分组的 npm script，上面的脚本可以进一步简化成</p><div class="language-js line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">npm</span><span style="color:#89DDFF;">-</span><span style="color:#A6ACCD;">run</span><span style="color:#89DDFF;">-</span><span style="color:#A6ACCD;">all xxx</span><span style="color:#89DDFF;">*</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="如何让多个-npm-script-并行执行" tabindex="-1">如何让多个 npm script 并行执行？ <a class="header-anchor" href="#如何让多个-npm-script-并行执行" aria-hidden="true">#</a></h3><div class="language-js line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">npm</span><span style="color:#89DDFF;">-</span><span style="color:#A6ACCD;">run</span><span style="color:#89DDFF;">-</span><span style="color:#A6ACCD;">all </span><span style="color:#89DDFF;">--</span><span style="color:#A6ACCD;">parallel </span><span style="color:#FFCB6B;">xxx</span><span style="color:#89DDFF;">:*</span><span style="color:#A6ACCD;"> </span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div>`,17);function u(C,D,y,A,b,_){const e=n("ArticleMetadata"),l=n("ClientOnly");return r(),t("div",null,[m,a(l,null,{default:i(()=>[a(e)]),_:1}),h])}const v=p(d,[["render",u]]);export{g as __pageData,v as default};
